#include <iostream>
#include <thread>
#include <mutex>
#include <vector>

class BankAccount {
private:
    int balance;
    std::mutex m1;
    std::mutex m2;
public:
    BankAccount() : balance(0) {}
    void deposit(int amount) {
        m1.lock();
        balance += amount;
        m1.unlock();
    }
    bool withdraw(int amount) {
        m2.lock();
        if (balance >= amount) {
            balance -= amount;
            m2.unlock();
            return true;
        } else {
            m2.unlock();
            return false;
        }
    }
    int getBalance() {
        int bal;
        m1.lock();
        m2.lock();
        bal = balance;
        m2.unlock();
        m1.unlock();
        return bal;
    }
};

void depositFunc(BankAccount& account) {
    for (int i = 0; i < 1000; i++) {
        account.deposit(1);
    }
}

void withdrawFunc(BankAccount& account) {
    for (int i = 0; i < 1000; i++) {
        account.withdraw(1);
    }
}

int main() {
    BankAccount account;
    std::thread t1(depositFunc, std::ref(account));
    std::thread t2(withdrawFunc, std::ref(account));
    t1.join();
    t2.join();
    std::cout << "Final balance: " << account.getBalance() << std::endl;
    return 0;
}

